	.TITLE	ZDEBUG	.PROC	M680002	.REF	SM8	.REF	FOS	.REF	BIOS	.REF	GESMEM	.REF	DRIVERS	.REF	LIB                   ; Constantes dans l'esclave; -------------------------ADZREG	=	O'40003		; contenu des registres du Z80ADZSTACK=	O'43777		; position du stack par dfaut; Registres du Z80; ----------------	.LOC	0OZI:	.BLKB	1		; IOZIY:	.BLKB	2		; IYOZIX:	.BLKB	2		; IXOZHLP:	.BLKB	2		; HL'OZDEP:	.BLKB	2		; DE'OZBCP:	.BLKB	2		; BC'OZFP:	.BLKB	1		; F'OZAP:	.BLKB	1		; A'OZHL:	.BLKB	2		; HLOZDE:	.BLKB	2		; DEOZBC:	.BLKB	2		; BCOZF:	.BLKB	1		; FOZA:	.BLKB	1		; AOZPC:	.BLKB	2		; PCOZSP:	.BLKB	2		; SPLZ:LBUUSA	=	5000LBULINE	=	16LBUFILE	=	32LBUBIN	=	LBUUSA; Variables; ---------	.LOC	0OCHIN:	.BLKB	2		; canal usart en lectureOCHOUT:	.BLKB	2		; canal usart en critureOBUUSA:	.BLKB	LBUUSA		; buffer pour l'usartOBULINE:.BLKB	LBULINE		; buffer de ligneOBUFILE:.BLKB	LBUFILE		; buffer de nom de fichierOBUBIN:	.BLKB	LBUBIN		; buffer pour un binaire	.BLKB	1OREG:	.BLKB	LZ		; registres du Z80	.EVENLGVAR:; Programme; ---------	.LOC	0START:	LIB	?OPELIB	LOAD.L	D4,#LGVAR	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM		; demande mmoire pour var.	JUMP,NE ERFAT	LOAD.L	A6,A4		; A6 <-- ^variables10$:	CLR.B	(A4+)		; met TOUTES les variables  zro	DEC.W	D4	JUMP,NE 10$	LIB	?AFTIM	.B	CR	.ASCIZ	"*** DEBUG hexadcimal pour esclave Z80 ***<CR><CR>"	.EVEN	CALL	USAOPEN		; ouvre les usarts	JUMP,NE ERRORLOOP:	LIB	?AFTIM	.B	CR	.ASCIZ	"(L)oad, (G)o, (S)tatus, (O)ut, (I)n, (R)ead, (W)rite, (E)dit, (END) : "	.EVEN	LIB	?GETCAR		; D3 <-- attend une touche ...	LIB	?MINMAJ		; D3 <-- en majuscule	LIB	?AFCODE	COMP.W	D3,#END	JUMP,EQ RETOUR	COMP.W	D3,#'L	JUMP,EQ DOLOAD	COMP.W	D3,#'G	JUMP,EQ DOGO	COMP.W	D3,#'S	JUMP,EQ DOSTATUS	COMP.W	D3,#'O	JUMP,EQ DOOUTPUT	COMP.W	D3,#'I	JUMP,EQ DOINPUT	COMP.W	D3,#'R	JUMP,EQ DOREAD	COMP.W	D3,#'W	JUMP,EQ DOWRITE	COMP.W	D3,#'E	JUMP,EQ DOEDITE	LOAD.W	D3,#BIPLIT	LIB	?BEEP		; p'tit bruit	JUMP	LOOPDOLOAD:	LIB	?AFTIM	.B	CR	.ASCIZ	"Nom du fichier  charger dans l'esclave : "	.EVEN	LOAD.L	A3,#(A6)+OBUFILE	LOAD.L	D3,#LBUFILE	LOAD.L	A4,A310$:	TEST.B	(A4+)	JUMP,EQ 15$	COMP.B	(A4)-1,#CR	JUMP,NE 10$15$:	DEC.L	A4	LOAD.L	A5,#0	LIB	?GETFILE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	LOADFILE	; charge le fichier ...	JUMP,NE ERROR	JUMP	LOOPDOGO:	LIB	?AFTIM	.B	CR	.ASCIZ	"C'est parti ..."	.EVEN	CALL	USAGO		; moteur ...	JUMP,NE ERROR	JUMP	LOOPDOSTATUS:	CALL	USARDREG	; lit les registres	JUMP,NE ERROR	LIB	?AFCR	LIB	?AFCR	CALL	AFREG		; puis affiche-les	JUMP	LOOPDOOUTPUT:	LIB	?AFTIM	.B	CR	.ASCIZ	"Adresse du priphrique : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- nombre octal	LOAD.W	D0,D4		; D0 <-- adresse $	LIB	?AFTIM	.ASCIZ	"Valeur  crire : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- nombre octal	LOAD.W	D3,D0	CALL	USAOUTPUT	JUMP,NE ERROR	JUMP	LOOPDOINPUT:	LIB	?AFTIM	.B	CR	.ASCIZ	"Adresse du priphrique : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- nombre octal	LOAD.W	D3,D4		; D3 <-- adresse $	CALL	USAINPUT	; D4 <-- byte lu	JUMP,NE ERROR	LIB	?AFTIM	.ASCIZ	"Byte lu = "	.EVEN	LIB	?AFX2	LIB	?AFCR	JUMP	LOOPDOREAD:	LIB	?AFTIM	.B	CR	.ASCIZ	"Nb de bytes  lire : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- nombre octal	TEST.W	D4	JUMP,EQ LOOP	JUMP,NS LOOP	COMP.W	D4,#16*10	JUMP,LS 20$	LOAD.W	D4,#16*1020$:	LOAD.W	D0,D4		; D0 <-- nb de bytes  lire	LIB	?AFTIM	.ASCIZ	"Adresse dans l'esclave : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- nombre octal	LOAD.W	D2,D440$:	LOAD.W	D1,#1650$:	LOAD.W	D3,D2		; D3 <-- adresse	CALL	USAREAD		; D4 <-- lit un byte ...	JUMP,NE ERROR	LIB	?AFX2	LIB	?AFSPACE	INC.W	D2		; D2 <-- adresse suivante	DEC.W	D0	JUMP,EQ 90$	DEC.W	D1	JUMP,NE 50$	LIB	?AFCR	JUMP	40$90$:	LIB	?AFCR	JUMP	LOOPDOWRITE:	LIB	?AFTIM	.B	CR	.ASCIZ	"Byte  crire dans l'esclave : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- byte octal	LOAD.W	D0,D4	LIB	?AFTIM	.ASCIZ	"Adresse dans l'esclave : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	GETX		; D4 <-- nombre octal	LOAD.W	D3,D4	LOAD.L	A4,#(A6)+OBULINE	LOAD.B	(A4),D0	LOAD.W	D4,#1	CALL	USAWRITE	; D3 <-- crit un byte ...	JUMP,NE ERROR	JUMP	LOOPDOEDITE:	LIB	?AFTIM	.B	CR	.ASCIZ	"Registre  modifier (par exemple: BC'=4000) : "	.EVEN	LOAD.L	A3,#(A6)+OBULINE	LOAD.W	D3,#LBULINE	LIB	?GETLINE	COMP.W	D3,#CR	JUMP,NE LOOP	CALL	EDITE	JUMP,NE ERROR	JUMP	LOOPERROR:	PUSH.W	D7	LIB	?AFTIM	.B	CR,AFINV,0	.EVEN	LOAD.W	D3,#BIPERR	LIB	?BEEP	POP.W	D7	LIB	?AFERROR	; affiche l'erreur	LIB	?AFTIM	.B	AFDIR,CR,0	.EVEN	JUMP	LOOPRETOUR:	CALL	USACLOSE	; ferme les usartsERFAT:	LIB	?CLOLIB	FOS	?STOP;---------\\; LOADFILE >;=========/; Charge un fichier dans le SMAKY100.; in	A3.L	^nom du fichier; out	D7.W	erreur; mod	D7.WLOADFILE:	PUSHM.L	D3,D4,D6,A3,A4	LOAD.L	A4,#R16"00$	CLR.W	D3	LIB	?ADDEXT		; ajoute ".CODE"	LOAD.W	D3,#2^BOPRD	FOS	?OPEN	JUMP,NE 90$	LOAD.L	A4,#(A6)+OBUBIN	LOAD.L	D4,#LBUBIN	FOS	?RDBYTE		; lit tout le fichier	JUMP,NE 20$	LOAD.W	D7,#ERNEMEM	JUMP	80$20$:	COMP.W	D7,#EROUTF	JUMP,NE 80$	FOS	?CLOSE	JUMP,NE 90$	LOAD.L	D3,(A4)+OBXSTA	; D3 <-- adresse de start	RR.W	D3,#8	LOAD.W	(A6)+OREG+OZPC,D3 ; init PC	LOAD.W	D3,#ADZSTACK	RR.W	D3,#8	LOAD.W	(A6)+OREG+OZSP,D3 ; init SP	CALL	USAWRREG	; crit tous les registres	JUMP,NE 90$	LOAD.L	D3,(A4)+OBXLOAD	; D3 <-- adresse de chargement	ADD.L	A4,#256	SUB.L	D4,#256	CALL	USAWRITE	; envoie tout le binaire ...	JUMP	90$80$:	PUSH.W	D7	FOS	?CLOSE	POP.W	D790$:	POPM.L	D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET00$:	.ASCIZ	".CODE"	.EVEN;--------\\; EDITE   >;========/; Modifie les registres selon une ligne de commande.; in	A3.L	^ligne de commande; out	D7.W	erreur; mod	D7.WEDITE:	PUSHM.L	D3,D4,A1..A4	LOAD.L	A4,#R16"00$	LOAD.W	D7,#ERSYNT	; D7 <-- erreur de sytaxe10$:	TEST.B	(A4)		; fin de la table ?	JUMP,EQ 90$		; oui => 90$				; non =>	LOAD.L	A2,A4	LOAD.L	A1,A320$:	LOAD.B	D3,(A1+)	JUMP,EQ 90$	LIB	?MINMAJ	COMP.B	D3,#'=	JUMP,EQ 30$	COMP.B	D3,(A2+)	JUMP,EQ 20$25$:	TEST.B	(A4+)		; A4 <-- saute .ASCIZ	JUMP,NE 25$	ADD.L	A4,#2		; A4 <-- saute .B (2x)	JUMP	10$30$:	TEST.B	(A2+)	JUMP,NE 25$	LOAD.L	A3,A1		; A3 <-- ^juste aprs le "="	CALL	GETX		; D4 <-- nouvelle valeur	LOAD.L	A4,#(A6)+OREG	; A4 <-- ^registres	CLR.W	D3	LOAD.B	D3,(A2)+0	LOAD.B	(A4)+(D3.W)+0,D4	COMP.B	(A2)+1,#2	JUMP,NE 80$	RR.W	D4,#8	LOAD.B	(A4)+(D3.W)+1,D480$:	CALL	USAWRREG	; crit tous les registres90$:	POPM.L	D3,D4,A1..A4	TEST.W	D7		; retour EQ/NE	RET00$:	.ASCIZ	"A"	.B	OZA,1	.ASCIZ	"F"	.B	OZF,1	.ASCIZ	"BC"	.B	OZBC,2	.ASCIZ	"B"	.B	OZBC+1,1	.ASCIZ	"C"	.B	OZBC+0,1	.ASCIZ	"DE"	.B	OZDE,2	.ASCIZ	"D"	.B	OZDE+1,1	.ASCIZ	"E"	.B	OZDE+0,1	.ASCIZ	"HL"	.B	OZHL,2	.ASCIZ	"H"	.B	OZHL+1,1	.ASCIZ	"L"	.B	OZHL+0,1	.ASCIZ	"A'"	.B	OZAP,1	.ASCIZ	"F'"	.B	OZFP,1	.ASCIZ	"BC'"	.B	OZBCP,2	.ASCIZ	"B'"	.B	OZBCP+1,2	.ASCIZ	"C'"	.B	OZBCP+0,1	.ASCIZ	"DE'"	.B	OZDEP,2	.ASCIZ	"D'"	.B	OZDEP+1,1	.ASCIZ	"E'"	.B	OZDEP+0,1	.ASCIZ	"HL'"	.B	OZHLP,2	.ASCIZ	"H'"	.B	OZHLP+1,1	.ASCIZ	"L'"	.B	OZHLP+0,1	.ASCIZ	"IX"	.B	OZIX,2	.ASCIZ	"IY"	.B	OZIY,2	.ASCIZ	"SP"	.B	OZSP,2	.ASCIZ	"PC"	.B	OZPC,2	.ASCIZ	"I"	.B	OZI,1	.B	0	.EVEN;--------\\; AFREG   >;========/; Affiche tous les registres.; in	-; out	-; mod	D7.WAFREG:	PUSHM.L	D4,A4	LIB	?BUCAR		; mode rapide	LOAD.L	A4,#(A6)+OREG	; A4 <-- ^tous les registres	LOAD.B	D4,(A4)+OZF	LIB	?AFB8		; F	LIB	?AFSPACE	LOAD.B	D4,(A4)+OZA	LIB	?AFX2		; A	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZBC	RR.W	D4,#8	LIB	?AFX4		; BC	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZDE	RR.W	D4,#8	LIB	?AFX4		; DE	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZHL	RR.W	D4,#8	LIB	?AFX4		; HL	LIB	?AFSPACE	LIB	?AFSPACE	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZSP	RR.W	D4,#8	LIB	?AFX4		; SP	LIB	?AFSPACE	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZPC	RR.W	D4,#8	LIB	?AFX4		; PC	LIB	?AFCR	LIB	?AFTIM	;	 11001010 00 0000 0000 0000   0000  0000	.ASCIZ	"SZ-H-VNC A   BC   DE   HL  IX SP IY PC I<CR>"	;	 10000001 00 0000 0000 0000 0000 0000  00	.EVEN	LOAD.B	D4,(A4)+OZFP	LIB	?AFB8		; F'	LIB	?AFSPACE	LOAD.B	D4,(A4)+OZAP	LIB	?AFX2		; A'	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZBCP	RR.W	D4,#8	LIB	?AFX4		; BC'	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZDEP	RR.W	D4,#8	LIB	?AFX4		; DE'	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZHLP	RR.W	D4,#8	LIB	?AFX4		; HL'	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZIX	RR.W	D4,#8	LIB	?AFX4		; IX	LIB	?AFSPACE	LOAD.W	D4,(A4)+OZIY	RR.W	D4,#8	LIB	?AFX4		; IY	LIB	?AFSPACE	LIB	?AFSPACE	LOAD.B	D4,(A4)+OZI	LIB	?AFX2		; I	LIB	?AFCR	LIB	?NOBUCAR	; remet le mode normal	POPM.L	D4,A4	RET;-------\\; GETX   >;=======/; Converti une chane ASCII hexadcimale en un nombre binaire.; in	A3.L	^nombre hexa en ASCII; out	D4.W	valeur binaire; mod	D4.LGETX:	PUSHM.L	D3,A3	CLR.W	D4		; D4 <-- futur nombre10$:	LOAD.B	D3,(A3+)	LIB	?MINMAJ	COMP.B	D3,#'0	JUMP,LO 90$	COMP.B	D3,#'9	JUMP,LS 40$	COMP.B	D3,#'A	JUMP,LO 90$	COMP.B	D3,#'F	JUMP,HI 90$	SUB.B	D3,#'A-10	; D3 <-- A..F	JUMP	50$40$:	SUB.B	D3,#'0		; D3 <-- 0..950$:	AND.W	D3,#H'FF	MUL.WU	D4,#16		; D4 <-- pousse d'un digit	ADD.W	D4,D3		; D4 <-- ajoute nouveau digit	JUMP	10$90$:	POPM.L	D3,A3	RET;-------\\; PUTX4  >;=======/; Converti un nombre binaire en une chane ASCII hexadcimale.; in	D4.B	nombre binaire;	A3.L	^buffer pour nombre hexa en ASCII; out	A3.L	^plus loin; mod	A3.LPUTX4:	RR.W	D4,#8	CALL	PUTX2	RR.W	D4,#8	RR.W	D4,#8;	CALL	PUTX2;	RET;-------\\; PUTX2  >;=======/; Converti un nombre binaire en une chane ASCII hexadcimale.; in	D4.B	nombre binaire;	A3.L	^buffer pour nombre hexa en ASCII; out	A3.L	^plus loin; mod	A3.LPUTX2:	PUSH.W	D3	LOAD.B	D3,D4	SR.B	D3,#4	ADD.B	D3,#'0	COMP.B	D3,#'9	JUMP,LS 20$	ADD.B	D3,#'A-'9-120$:	LOAD.B	(A3+),D3	LOAD.B	D3,D4	AND.B	D3,#H'0F	ADD.B	D3,#'0	COMP.B	D3,#'9	JUMP,LS 40$	ADD.B	D3,#'A-'9-140$:	LOAD.B	(A3+),D3	POP.W	D3	RET;---------\\; USAWRREG >;=========/; Ecrit tous les registres dans le Z80.; in	-; out	D7.W	erreur; mod	D7.WUSAWRREG:	PUSHM.L	D3,D4,A4	LOAD.L	A4,#(A6)+OREG	LOAD.W	D4,#LZ	LOAD.W	D3,#ADZREG	; D3 <-- adresse des registres	CALL	USAWRITE	; crit tous les registres	POPM.L	D3,D4,A4	TEST.W	D7		; retour EQ/NE	RET;---------\\; USARDREG >;=========/; Lit tous les registres du Z80.; in	-; out	D7.W	erreur; mod	D7.WUSARDREG:	PUSHM.L	D2..D4,A4	LOAD.L	A4,#(A6)+OREG	LOAD.W	D3,#ADZREG	; D3 <-- adresse des registres	LOAD.W	D2,#LZ-1	; D2 <-- -1  cause NMO10$:	CALL	USAREAD		; D4 <-- lit un byte	JUMP,NE 90$	LOAD.B	(A4+),D4	INC.W	D3		; D3 <-- adresse suivante	DECJ.W,NMO D2,10$90$:	POPM.L	D2..D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; USAGO   >;========/; Excute un programme dans l'esclave.; in	-; out	D7.W	erreur; mod	D7.WUSAGO:	PUSHM.L	D3,D4,D6,A3,A4	LOAD.L	A3,#(A6)+OBUUSA	LOAD.B	(A3+),#4	; <4>	CLR.B	(A3+)		; <0>	LOAD.L	A4,#(A6)+OBUUSA	LOAD.L	D4,A3	SUB.L	D4,A4		; D4 <-- nb bytes  crire	LOAD.W	D6,(A6)+OCHOUT	FOS	?WRBYTE		; crit le tout	JUMP,NE 90$40$:	LOAD.B	D3,#'.	LIB	?AFCAR	LIB	?IFCAR		; une touche presse ?	JUMP,EQ 80$		; oui => 80$	CALL	RDONE		; D4 <-- lit un byte	JUMP,NE 40$	COMP.B	D4,#O'367	JUMP,NE 40$	CALL	USARDREG	; lit les registres	LIB	?AFCR	CALL	AFREG		; puis afiche-les80$:	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;----------\\; USAOUTPUT >;==========/   ; Ecrit un byte dans un priphrique de l'esclave.; in	D4.B	byte  crire;	D3.W	adresse dans l'esclave; out	D7.W	erreur; mod	D7.WUSAOUTPUT:	PUSHM.L	D3,D4,D6,A3,A4	LOAD.L	A3,#(A6)+OBUUSA	LOAD.B	(A3+),#5	; <5>	CLR.B	(A3+)		; <0>	LOAD.B	(A3+),D3	; <adresse $>	LOAD.B	(A3+),D4	; <data>	CLR.B	(A3+)		; <0>	LOAD.L	A4,#(A6)+OBUUSA	LOAD.L	D4,A3	SUB.L	D4,A4		; D4 <-- nb bytes  crire	LOAD.W	D6,(A6)+OCHOUT	FOS	?WRBYTE		; crit le tout	POPM.L	D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\\; USAINPUT >;=========/; Lit un byte dans un priphrique de l'esclave.; in	D3.W	adresse dans l'esclave; out	D4.B	byte lu;	D7.W	erreur; mod	D4.L, D7.WUSAINPUT:	PUSHM.L	D3,D6,A3,A4	LOAD.L	A3,#(A6)+OBUUSA	LOAD.B	(A3+),#6	; <6>	CLR.B	(A3+)		; <0>	LOAD.B	(A3+),D3	; <adresse $>	CLR.B	(A3+)		; <0>	CLR.B	(A3+)		; <0>	LOAD.L	A4,#(A6)+OBUUSA	LOAD.L	D4,A3	SUB.L	D4,A4		; D4 <-- nb bytes  crire	LOAD.W	D6,(A6)+OCHOUT	FOS	?WRBYTE		; crit le tout	JUMP,NE 90$40$:	CALL	RDONE		; D4 <-- lit un byte	JUMP,NE 90$	COMP.B	D4,#6	JUMP,NE 40$	CALL	RDONE		; D4 <-- lit le byte de data90$:	POPM.L	D3,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\\; USAWRITE >;=========/; Ecrit un ou plusieurs bytes dans l'esclave.; in	A4.L	^bytes  crire;	D4.W	nb de bytes  crire (1..n);	D3.W	adresse dans l'esclave; out	D7.W	erreur; mod	D7.WUSAWRITE:	PUSHM.L	D3,D4,D6,A3,A4	LOAD.L	A3,#(A6)+OBUUSA	LOAD.B	(A3+),#3	; <3>	CLR.B	(A3+)		; <0>	LOAD.B	(A3+),D3	; <adresse low>	RR.W	D3,#8	LOAD.B	(A3+),D3	; <adresse high>	LOAD.W	D3,D4	LOAD.B	(A3+),D3	; <nb bytes low>	RR.W	D3,#8	LOAD.B	(A3+),D3	; <nb bytes high>20$:	LOAD.B	(A3+),(A4+)	; <data>	DEC.W	D4	JUMP,NE 20$	LOAD.L	A4,#(A6)+OBUUSA	LOAD.L	D4,A3	SUB.L	D4,A4		; D4 <-- nb bytes  crire	LOAD.W	D6,(A6)+OCHOUT	FOS	?WRBYTE		; crit le tout	POPM.L	D3,D4,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; USAREAD >;========/; Lit un byte dans l'esclave.; in	D3.W	adresse dans l'esclave; out	D4.B	byte reu;	D7.W	erreur; mod	D4.L, D7.WUSAREAD:	PUSHM.L	D3,D6,A3,A4	LOAD.L	A3,#(A6)+OBUUSA	LOAD.B	(A3+),#2	; <2>	CLR.B	(A3+)		; <0>	LOAD.B	(A3+),D3	; <adresse low>	RR.W	D3,#8	LOAD.B	(A3+),D3	; <adresse high>	CLR.B	(A3+)		; <0>	LOAD.L	A4,#(A6)+OBUUSA	LOAD.L	D4,A3	SUB.L	D4,A4		; D4 <-- nb bytes  crire	LOAD.W	D6,(A6)+OCHOUT	FOS	?WRBYTE		; crit le tout	JUMP,NE 90$40$:	CALL	RDONE		; D4 <-- lit un byte	JUMP,NE 90$	COMP.B	D4,#2	JUMP,NE 40$	CALL	RDONE		; D4 <-- lit le byte de data90$:	POPM.L	D3,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; RDONE   >;========/; Lit un byte de l'usart.; in	-; out	D4.B	byte lu;	D7.W	erreur; mod	D4.L, D7.WRDONE:	PUSHM.L	D3,D6,A4	LOAD.L	A4,#(A6)+OBUUSA	LOAD.L	D4,#1		; D4 <-- lit un seul byte	LOAD.W	D6,(A6)+OCHIN	FOS	?RDBYTE		; attend un byte ...	JUMP,NE 90$	LOAD.B	D4,(A4)		; D4 <-- byte lu90$:	POPM.L	D3,D6,A4	TEST.W	D7		; retour EQ/NE	RET;--------\\; USAOPEN >;========/; Ouvre les usarts en lecture et en criture.; in	-; out	D7.W	erreur; mod	D7.WUSAOPEN:	PUSHM.L	D3,D6,A3,A4	LOAD.L	A3,#R16"NUSAIN	LOAD.W	D3,#2^BOPRD	FOS	?OPEN		; ouvre en lecture	JUMP,NE 90$	LOAD.W	(A6)+OCHIN,D6	LOAD.L	A3,#R16"NUSAOUT	LOAD.W	D3,#2^BOPWR	FOS	?OPEN		; ouvre en criture	JUMP,NE 90$	LOAD.W	(A6)+OCHOUT,D6	LOAD.L	A4,#R16"CUSAIN	LOAD.W	D3,#TYPIO	LOAD.W	D6,(A6)+OCHIN	FOS	?COMMAND	; met un timeout d'une seconde90$:	POPM.L	D3,D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\\; USACLOSE >;=========/; Ferme les usarts en lecture et en criture.; in	-; out	-; mod	D7.WUSACLOSE:	PUSH.L	D6	LOAD.W	D6,(A6)+OCHIN	JUMP,EQ 20$	FOS	?CLOSE		; ferme en lecture20$:	LOAD.W	D6,(A6)+OCHOUT	JUMP,EQ 40$	FOS	?CLOSE		; ferme en criture40$:	POP.L	D6	RETNUSAIN:	.ASCIZ	"#PR"NUSAOUT:.ASCIZ	"#PP"CUSAIN:	.ASCIZ	"YET50"		; timeout d'une seconde	.EVENVAR:	.FILLB	LGVAR,0	.END	START